#pragma OPENCL EXTENSION cl_khr_fp64 : enable

#define PI 3.1415926535897932
#define M 2147483647
#define A 1103515245
#define C 12345

inline double roundDouble(double value) {
    int newValue = (int)(value);
    if (value - (double)newValue < 0.5)
        return (double)newValue;
    else
        return (double)newValue; // preserves original post-increment bug behavior
}

inline double randu(__global int *seed, int index) {
    int num = A * seed[index] + C;
    seed[index] = num % M;
    return fabs((double)seed[index] / (double)M);
}

inline double randn(__global int *seed, int index) {
    double u = randu(seed, index);
    double v = randu(seed, index);
    double cosine = cos(2.0 * PI * v);
    double rt = -2.0 * log(u);
    return sqrt(rt) * cosine;
}

__kernel void likelihood_kernel(
    __global double *arrayX,
    __global double *arrayY,
    __global double *xj,
    __global double *yj,
    __global double *CDF,
    __global int *ind,
    __global int *objxy,
    __global double *likelihood,
    __global unsigned char *I,
    __global double *u,
    __global double *weights,
    int Nparticles,
    int countOnes,
    int max_size,
    int k,
    int IszY,
    int Nfr,
    __global int *seed,
    __global double *partial_sums,
    __local double *buffer
) {
    int i = get_global_id(0);
    if (i >= Nparticles) return;

    arrayX[i] = xj[i] + 1.0 + 5.0 * randn(seed, i);
    arrayY[i] = yj[i] - 2.0 + 2.0 * randn(seed, i);

    double lik = 0.0;
    for (int y = 0; y < countOnes; y++) {
        int indX = (int)roundDouble(arrayX[i]) + objxy[y * 2 + 1];
        int indY = (int)roundDouble(arrayY[i]) + objxy[y * 2];
        int index = abs(indX * IszY * Nfr + indY * Nfr + k);
        if (index >= max_size) index = 0;
        ind[i * countOnes + y] = index;

        double a = (double)((int)I[index] - 100);
        double b = (double)((int)I[index] - 228);
        lik += (a * a - b * b) / 50.0;
    }
    lik = lik / (double)countOnes;
    likelihood[i] = lik;

    weights[i] = weights[i] * exp(lik);
    partial_sums[i] = weights[i];

    (void)CDF;
    (void)u;
    (void)buffer;
}

__kernel void sum_kernel(__global double *partial_sums, int Nparticles) {
    int gid = get_global_id(0);
    if (gid != 0) return;

    double s = 0.0;
    for (int i = 0; i < Nparticles; i++) {
        s += partial_sums[i];
    }
    partial_sums[0] = s;
}

__kernel void normalize_weights_kernel(
    __global double *weights,
    int Nparticles,
    __global double *partial_sums,
    __global double *CDF,
    __global double *u,
    __global int *seed
) {
    int gid = get_global_id(0);
    if (gid != 0) return;

    double sumWeights = partial_sums[0];
    if (sumWeights == 0.0) sumWeights = 1.0;

    for (int i = 0; i < Nparticles; i++) {
        weights[i] = weights[i] / sumWeights;
    }

    if (Nparticles > 0) {
        CDF[0] = weights[0];
        for (int i = 1; i < Nparticles; i++) {
            CDF[i] = weights[i] + CDF[i - 1];
        }

        double u1 = (1.0 / (double)Nparticles) * randu(seed, 0);
        for (int i = 0; i < Nparticles; i++) {
            u[i] = u1 + ((double)i / (double)Nparticles);
        }
    }
}

__kernel void find_index_kernel(
    __global double *arrayX,
    __global double *arrayY,
    __global double *CDF,
    __global double *u,
    __global double *xj,
    __global double *yj,
    __global double *weights,
    int Nparticles
) {
    int j = get_global_id(0);
    if (j >= Nparticles) return;

    int index = -1;
    double value = u[j];
    for (int x = 0; x < Nparticles; x++) {
        if (CDF[x] >= value) {
            index = x;
            break;
        }
    }
    if (index == -1) index = Nparticles - 1;

    xj[j] = arrayX[index];
    yj[j] = arrayY[index];
    weights[j] = 1.0 / (double)Nparticles;
}

